const crypto = require('crypto');
const http = require('http');
const fs = require('fs');
const path = require('path');

// ========== WebSocket Protocol (RFC 6455) ==========

const OPCODES = { TEXT: 0x01, CLOSE: 0x08, PING: 0x09, PONG: 0x0A };
const WS_MAGIC = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11';

function computeAcceptKey(clientKey) {
  return crypto.createHash('sha1').update(clientKey + WS_MAGIC).digest('base64');
}

function encodeFrame(opcode, payload) {
  const fin = 0x80;
  const len = payload.length;
  let header;

  if (len < 126) {
    header = Buffer.alloc(2);
    header[0] = fin | opcode;
    header[1] = len;
  } else if (len < 65536) {
    header = Buffer.alloc(4);
    header[0] = fin | opcode;
    header[1] = 126;
    header.writeUInt16BE(len, 2);
  } else {
    header = Buffer.alloc(10);
    header[0] = fin | opcode;
    header[1] = 127;
    header.writeBigUInt64BE(BigInt(len), 2);
  }

  return Buffer.concat([header, payload]);
}

function decodeFrame(buffer) {
  if (buffer.length < 2) return null;

  const secondByte = buffer[1];
  const opcode = buffer[0] & 0x0F;
  const masked = (secondByte & 0x80) !== 0;
  let payloadLen = secondByte & 0x7F;
  let offset = 2;

  if (!masked) throw new Error('Client frames must be masked');

  if (payloadLen === 126) {
    if (buffer.length < 4) return null;
    payloadLen = buffer.readUInt16BE(2);
    offset = 4;
  } else if (payloadLen === 127) {
    if (buffer.length < 10) return null;
    payloadLen = Number(buffer.readBigUInt64BE(2));
    offset = 10;
  }

  const maskOffset = offset;
  const dataOffset = offset + 4;
  const totalLen = dataOffset + payloadLen;
  if (buffer.length < totalLen) return null;

  const mask = buffer.slice(maskOffset, dataOffset);
  const data = Buffer.alloc(payloadLen);
  for (let i = 0; i < payloadLen; i++) {
    data[i] = buffer[dataOffset + i] ^ mask[i % 4];
  }

  return { opcode, payload: data, bytesConsumed: totalLen };
}

// ========== Configuration ==========

const PORT = process.env.BRAINSTORM_PORT || (49152 + Math.floor(Math.random() * 16383));
const HOST = process.env.BRAINSTORM_HOST || '127.0.0.1';
const URL_HOST = process.env.BRAINSTORM_URL_HOST || (HOST === '127.0.0.1' ? 'localhost' : HOST);
const SCREEN_DIR = process.env.BRAINSTORM_DIR || '/tmp/brainstorm';
const OWNER_PID = process.env.BRAINSTORM_OWNER_PID ? Number(process.env.BRAINSTORM_OWNER_PID) : null;

const MIME_TYPES = {
  '.html': 'text/html', '.css': 'text/css', '.js': 'application/javascript',
  '.json': 'application/json', '.png': 'image/png', '.jpg': 'image/jpeg',
  '.jpeg': 'image/jpeg', '.gif': 'image/gif', '.svg': 'image/svg+xml'
};

// ========== Templates and Constants ==========

const WAITING_PAGE = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"><title>Visual Companion</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html, body { height: 100%; }
  html {
    background-color: #f6f5f3;
    background-image: radial-gradient(circle, #c5c0b5 1.2px, transparent 1.2px);
    background-size: 20px 20px;
  }
  body {
    font-family: system-ui, -apple-system, sans-serif;
    background: transparent;
    color: #2c2c2e;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .container {
    text-align: center;
    max-width: 400px;
    position: relative;
  }
  .crosshair {
    font-family: monospace;
    font-size: 14px;
    color: #d4d0c8;
    margin-bottom: 1.5rem;
    letter-spacing: 2em;
  }
  h1 {
    font-size: 0.8rem;
    font-weight: 500;
    color: #8a8780;
    text-transform: uppercase;
    letter-spacing: 0.08em;
    margin-bottom: 0.75rem;
  }
  p {
    font-size: 0.85rem;
    color: #b0aca4;
    font-family: monospace;
    line-height: 1.6;
  }
  .spinner {
    display: inline-block;
    width: 8px;
    height: 8px;
    border: 1px solid #d4d0c8;
    margin-top: 1.5rem;
    animation: vc-pulse 1.2s ease-in-out infinite;
  }
  @media (prefers-color-scheme: dark) {
    html { background-color: #1a1a1c; background-image: radial-gradient(circle, #4a4945 1.2px, transparent 1.2px); background-size: 20px 20px; }
    body { color: #f0efed; }
    .crosshair { color: #424143; }
    h1 { color: #8e8b86; }
    p { color: #5e5b56; }
    .spinner { border-color: #424143; }
  }
  @keyframes vc-pulse { 0%, 100% { opacity: 0.2; } 50% { opacity: 0.8; } }
</style>
</head>
<body>
  <div class="container">
    <div class="crosshair">+</div>
    <h1>Visual Companion</h1>
    <p>Waiting for the agent to push a screen...</p>
    <div class="spinner"></div>
  </div>
</body>
</html>`;

const frameTemplate = fs.readFileSync(path.join(__dirname, 'frame-template.html'), 'utf-8');
const helperScript = fs.readFileSync(path.join(__dirname, 'helper.js'), 'utf-8');
const helperInjection = '<script>\n' + helperScript + '\n</script>';

// ========== Helper Functions ==========

function isFullDocument(html) {
  const trimmed = html.trimStart().toLowerCase();
  return trimmed.startsWith('<!doctype') || trimmed.startsWith('<html');
}

function wrapInFrame(content) {
  return frameTemplate.replace('<!-- CONTENT -->', content);
}

function getNewestScreen() {
  const files = fs.readdirSync(SCREEN_DIR)
    .filter(f => f.endsWith('.html'))
    .map(f => {
      const fp = path.join(SCREEN_DIR, f);
      return { path: fp, mtime: fs.statSync(fp).mtime.getTime() };
    })
    .sort((a, b) => b.mtime - a.mtime);
  return files.length > 0 ? files[0].path : null;
}

// ========== HTTP Request Handler ==========

function handleRequest(req, res) {
  touchActivity();
  if (req.method === 'GET' && req.url === '/') {
    const screenFile = getNewestScreen();
    let html = screenFile
      ? (raw => isFullDocument(raw) ? raw : wrapInFrame(raw))(fs.readFileSync(screenFile, 'utf-8'))
      : WAITING_PAGE;

    if (html.includes('</body>')) {
      html = html.replace('</body>', helperInjection + '\n</body>');
    } else {
      html += helperInjection;
    }

    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(html);
  } else if (req.method === 'GET' && req.url.startsWith('/files/')) {
    const fileName = req.url.slice(7);
    const filePath = path.join(SCREEN_DIR, path.basename(fileName));
    if (!fs.existsSync(filePath)) {
      res.writeHead(404);
      res.end('Not found');
      return;
    }
    const ext = path.extname(filePath).toLowerCase();
    const contentType = MIME_TYPES[ext] || 'application/octet-stream';
    res.writeHead(200, { 'Content-Type': contentType });
    res.end(fs.readFileSync(filePath));
  } else if (req.method === 'GET' && req.url === '/api/wait') {
    // Long-poll: blocks until a selection is made on the current screen
    decisionPromise.then((decision) => {
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify(decision));
    });
    req.on('close', () => {
      // Client disconnected — no cleanup needed
    });
  } else if (req.method === 'POST' && req.url === '/api/select') {
    // HTTP fallback for selection (primary path is WebSocket)
    let body = '';
    req.on('data', (chunk) => { body += chunk; });
    req.on('end', () => {
      try {
        const data = JSON.parse(body);
        if (data.choice && resolveDecision) {
          resolveDecision(data);
        }
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ ok: true }));
      } catch (e) {
        res.writeHead(400, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ error: 'Invalid JSON' }));
      }
    });
  } else {
    res.writeHead(404);
    res.end('Not found');
  }
}

// ========== WebSocket Connection Handling ==========

const clients = new Set();

function handleUpgrade(req, socket) {
  const key = req.headers['sec-websocket-key'];
  if (!key) { socket.destroy(); return; }

  const accept = computeAcceptKey(key);
  socket.write(
    'HTTP/1.1 101 Switching Protocols\r\n' +
    'Upgrade: websocket\r\n' +
    'Connection: Upgrade\r\n' +
    'Sec-WebSocket-Accept: ' + accept + '\r\n\r\n'
  );

  let buffer = Buffer.alloc(0);
  clients.add(socket);

  socket.on('data', (chunk) => {
    buffer = Buffer.concat([buffer, chunk]);
    while (buffer.length > 0) {
      let result;
      try {
        result = decodeFrame(buffer);
      } catch (e) {
        socket.end(encodeFrame(OPCODES.CLOSE, Buffer.alloc(0)));
        clients.delete(socket);
        return;
      }
      if (!result) break;
      buffer = buffer.slice(result.bytesConsumed);

      switch (result.opcode) {
        case OPCODES.TEXT:
          handleMessage(result.payload.toString());
          break;
        case OPCODES.CLOSE:
          socket.end(encodeFrame(OPCODES.CLOSE, Buffer.alloc(0)));
          clients.delete(socket);
          return;
        case OPCODES.PING:
          socket.write(encodeFrame(OPCODES.PONG, result.payload));
          break;
        case OPCODES.PONG:
          break;
        default: {
          const closeBuf = Buffer.alloc(2);
          closeBuf.writeUInt16BE(1003);
          socket.end(encodeFrame(OPCODES.CLOSE, closeBuf));
          clients.delete(socket);
          return;
        }
      }
    }
  });

  socket.on('close', () => clients.delete(socket));
  socket.on('error', () => clients.delete(socket));
}

function handleMessage(text) {
  let event;
  try {
    event = JSON.parse(text);
  } catch (e) {
    console.error('Failed to parse WebSocket message:', e.message);
    return;
  }
  touchActivity();
  console.log(JSON.stringify({ source: 'user-event', ...event }));
  if (event.choice) {
    const eventsFile = path.join(SCREEN_DIR, '.events');
    fs.appendFileSync(eventsFile, JSON.stringify(event) + '\n');
    // Resolve decision promise so /api/wait returns immediately
    if (resolveDecision) resolveDecision(event);
  }
}

function broadcast(msg) {
  const frame = encodeFrame(OPCODES.TEXT, Buffer.from(JSON.stringify(msg)));
  for (const socket of clients) {
    try { socket.write(frame); } catch (e) { clients.delete(socket); }
  }
}

// ========== Activity Tracking ==========

const IDLE_TIMEOUT_MS = 30 * 60 * 1000; // 30 minutes
let lastActivity = Date.now();

function touchActivity() {
  lastActivity = Date.now();
}

// ========== Decision Promise (Plannotator-style wait) ==========

let resolveDecision = null;
let decisionPromise = null;

function resetDecision() {
  decisionPromise = new Promise((r) => { resolveDecision = r; });
}

resetDecision();

// ========== File Watching ==========

const debounceTimers = new Map();

// ========== Server Startup ==========

function startServer() {
  if (!fs.existsSync(SCREEN_DIR)) fs.mkdirSync(SCREEN_DIR, { recursive: true });

  // Track known files to distinguish new screens from updates.
  // macOS fs.watch reports 'rename' for both new files and overwrites,
  // so we can't rely on eventType alone.
  const knownFiles = new Set(
    fs.readdirSync(SCREEN_DIR).filter(f => f.endsWith('.html'))
  );

  const server = http.createServer(handleRequest);
  server.on('upgrade', handleUpgrade);

  const watcher = fs.watch(SCREEN_DIR, (eventType, filename) => {
    if (!filename || !filename.endsWith('.html')) return;

    // Reset decision immediately for new screens (before debounce).
    // The 100ms debounce could delay resetDecision long enough that a
    // subsequent wait-for-decision reads a stale resolved promise.
    if (!knownFiles.has(filename)) {
      resetDecision();
    }

    if (debounceTimers.has(filename)) clearTimeout(debounceTimers.get(filename));
    debounceTimers.set(filename, setTimeout(() => {
      debounceTimers.delete(filename);
      const filePath = path.join(SCREEN_DIR, filename);

      if (!fs.existsSync(filePath)) return; // file was deleted
      touchActivity();

      if (!knownFiles.has(filename)) {
        knownFiles.add(filename);
        const eventsFile = path.join(SCREEN_DIR, '.events');
        if (fs.existsSync(eventsFile)) fs.unlinkSync(eventsFile);
        resetDecision(); // New screen → reset decision promise
        console.log(JSON.stringify({ type: 'screen-added', file: filePath }));
      } else {
        console.log(JSON.stringify({ type: 'screen-updated', file: filePath }));
      }

      broadcast({ type: 'reload' });
    }, 100));
  });
  watcher.on('error', (err) => console.error('fs.watch error:', err.message));

  function shutdown(reason) {
    console.log(JSON.stringify({ type: 'server-stopped', reason }));
    const infoFile = path.join(SCREEN_DIR, '.server-info');
    if (fs.existsSync(infoFile)) fs.unlinkSync(infoFile);
    fs.writeFileSync(
      path.join(SCREEN_DIR, '.server-stopped'),
      JSON.stringify({ reason, timestamp: Date.now() }) + '\n'
    );
    watcher.close();
    clearInterval(lifecycleCheck);
    server.close(() => process.exit(0));
  }

  function ownerAlive() {
    if (!OWNER_PID) return true;
    try { process.kill(OWNER_PID, 0); return true; } catch (e) { return false; }
  }

  // Check every 60s: exit if owner process died or idle for 30 minutes
  const lifecycleCheck = setInterval(() => {
    if (!ownerAlive()) shutdown('owner process exited');
    else if (Date.now() - lastActivity > IDLE_TIMEOUT_MS) shutdown('idle timeout');
  }, 60 * 1000);
  lifecycleCheck.unref();

  server.listen(PORT, HOST, () => {
    const info = JSON.stringify({
      type: 'server-started', port: Number(PORT), host: HOST,
      url_host: URL_HOST, url: 'http://' + URL_HOST + ':' + PORT,
      screen_dir: SCREEN_DIR
    });
    console.log(info);
    fs.writeFileSync(path.join(SCREEN_DIR, '.server-info'), info + '\n');
  });
}

if (require.main === module) {
  startServer();
}

module.exports = { computeAcceptKey, encodeFrame, decodeFrame, OPCODES };

(function() {
  const WS_URL = 'ws://' + window.location.host;
  let ws = null;
  let eventQueue = [];

  // --- Per-option feedback storage ---
  const feedbackMap = new Map();
  let currentChoice = null;

  function connect() {
    ws = new WebSocket(WS_URL);

    ws.onopen = () => {
      eventQueue.forEach(e => ws.send(JSON.stringify(e)));
      eventQueue = [];
    };

    ws.onmessage = (msg) => {
      const data = JSON.parse(msg.data);
      if (data.type === 'reload') {
        window.location.reload();
      }
    };

    ws.onclose = () => {
      setTimeout(connect, 1000);
    };
  }

  function sendEvent(event) {
    event.timestamp = Date.now();
    if (ws && ws.readyState === WebSocket.OPEN) {
      ws.send(JSON.stringify(event));
    } else {
      eventQueue.push(event);
    }
  }

  // --- V2: Sidebar + Toggle Logic ---

  let selectedChoice = null;

  function initV2() {
    const options = document.querySelectorAll('.option[data-choice]');
    const toggle = document.getElementById('vc-toggle');
    const dialog = document.getElementById('vc-dialog');
    const island = document.getElementById('vc-island');

    if (!options.length || !toggle || !dialog) return;

    // Show the floating toggle button + island
    toggle.style.display = 'block';
    if (island) island.style.display = 'flex';

    // Toggle dialog open/close
    toggle.addEventListener('click', () => {
      const isOpen = dialog.classList.toggle('open');
      toggle.classList.toggle('active', isOpen);
    });

    // IntersectionObserver: track which option is visible
    const observer = new IntersectionObserver((entries) => {
      for (const entry of entries) {
        if (entry.isIntersecting) {
          const option = entry.target;
          const choice = option.dataset.choice;

          // Save current feedback before switching
          saveFeedback();

          currentChoice = choice;
          updateSidebarMetadata(option);
          restoreFeedback(choice);
          updateIsland();

          // Update select button state based on whether current option is the selected one
          const selectBtn = document.getElementById('vc-select');
          if (selectBtn) {
            if (selectedChoice === choice) {
              selectBtn.textContent = 'Selected \u2714';
              selectBtn.style.background = 'var(--success)';
            } else {
              selectBtn.textContent = 'Select';
              selectBtn.style.background = '';
            }
          }
        }
      }
    }, { threshold: 0.5 });

    options.forEach(option => observer.observe(option));

    // Initialize with first option
    if (options[0]) {
      currentChoice = options[0].dataset.choice;
      updateSidebarMetadata(options[0]);
    }

    // Select button
    const selectBtn = document.getElementById('vc-select');
    if (selectBtn) {
      selectBtn.addEventListener('click', () => {
        if (!currentChoice) return;

        // Save feedback text
        saveFeedback();
        const feedbackText = feedbackMap.get(currentChoice) || '';

        // Remove selected from all, add to current
        options.forEach(o => o.classList.remove('selected'));
        const current = document.querySelector(`.option[data-choice="${currentChoice}"]`);
        if (current) current.classList.add('selected');

        // Build event
        const event = {
          type: 'click',
          choice: currentChoice,
          text: current ? current.dataset.title || currentChoice : currentChoice,
          id: current ? current.id || null : null
        };
        if (feedbackText) event.feedback = feedbackText;

        sendEvent(event);

        // Also POST to /api/select as HTTP fallback (resolves decision promise server-side)
        fetch('/api/select', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify(event)
        }).catch(function() {
          // WebSocket is primary; HTTP is a best-effort fallback
        });

        // Track selection
        selectedChoice = currentChoice;
        updateIsland();

        // Update Select button to confirmed state
        selectBtn.textContent = 'Selected \u2714';
        selectBtn.style.background = 'var(--success)';

        // Show auto-close overlay (Plannotator-style)
        showSelectionOverlay(current ? current.dataset.title || currentChoice : currentChoice);

      });
    }
  }

  function showSelectionOverlay(selectedTitle) {
    var overlay = document.createElement('div');
    overlay.id = 'vc-selection-overlay';
    overlay.className = 'vc-overlay';
    overlay.innerHTML =
      '<div class="vc-overlay-bg"></div>' +
      '<div class="vc-overlay-inner">' +
        '<div class="vc-overlay-icon">' +
          '<svg viewBox="0 0 24 24"><polyline points="20 6 9 17 4 12"/></svg>' +
        '</div>' +
        '<h2 class="vc-overlay-title">Selected</h2>' +
        '<p class="vc-overlay-subtitle">' + escapeHtml(selectedTitle) + '</p>' +
        '<p class="vc-overlay-status" id="vc-close-status">Closing in 3s...</p>' +
      '</div>';
    document.body.appendChild(overlay);

    function tryClose(callback) {
      window.close();
      setTimeout(function() {
        if (!window.closed) {
          callback();
        }
      }, 300);
    }

    // Countdown: 3... 2... 1... close
    var remaining = 3;
    var statusEl = document.getElementById('vc-close-status');
    var timer = setInterval(function() {
      remaining--;
      if (remaining > 0) {
        if (statusEl) statusEl.textContent = 'Closing in ' + remaining + 's...';
      } else {
        clearInterval(timer);
        if (statusEl) statusEl.textContent = '';
        tryClose(function() {
          if (statusEl) {
            statusEl.innerHTML = '';
          }
          // Add a visible close button
          var closeBtn = document.createElement('button');
          closeBtn.textContent = 'Close Tab';
          closeBtn.className = 'vc-overlay-btn';
          closeBtn.onclick = function() { try { window.close(); } catch(e) {} };
          overlay.querySelector('.vc-overlay-inner').appendChild(closeBtn);
        });
      }
    }, 1000);
  }

  function escapeHtml(str) {
    var div = document.createElement('div');
    div.appendChild(document.createTextNode(str));
    return div.innerHTML;
  }

  function updateIsland() {
    const island = document.getElementById('vc-island');
    const selText = document.getElementById('vc-island-selection-text');
    if (!island || !selText) return;

    if (selectedChoice && currentChoice === selectedChoice) {
      const selOption = document.querySelector(`.option[data-choice="${selectedChoice}"]`);
      const title = selOption?.dataset.title || selectedChoice;
      selText.textContent = '\u2714 ' + title;
      island.classList.add('has-selection');
    } else {
      island.classList.remove('has-selection');
    }
  }

  function updateSidebarMetadata(option) {
    const letter = document.getElementById('vc-letter');
    const title = document.getElementById('vc-title');
    const desc = document.getElementById('vc-description');

    if (letter) letter.textContent = option.dataset.choice || '?';
    if (title) title.textContent = option.dataset.title || 'Option ' + (option.dataset.choice || '');
    if (desc) desc.textContent = option.dataset.description || '';
  }

  function saveFeedback() {
    if (!currentChoice) return;
    const textarea = document.getElementById('vc-feedback');
    if (textarea) {
      feedbackMap.set(currentChoice, textarea.value);
    }
  }

  function restoreFeedback(choice) {
    const textarea = document.getElementById('vc-feedback');
    if (textarea) {
      textarea.value = feedbackMap.get(choice) || '';
    }
  }

  // --- Legacy: Click selection for .cards and non-v2 .options ---

  document.addEventListener('click', (e) => {
    const target = e.target.closest('[data-choice]');
    if (!target) return;

    // Skip if inside v2 options (handled by sidebar Select button)
    if (target.closest('.options') && document.querySelector('.option[data-choice]')) return;

    sendEvent({
      type: 'click',
      text: target.textContent.trim(),
      choice: target.dataset.choice,
      id: target.id || null
    });

    // Update indicator bar
    setTimeout(() => {
      const indicator = document.getElementById('indicator-text');
      if (!indicator) return;
      const container = target.closest('.cards');
      const selected = container ? container.querySelectorAll('.selected') : [];
      if (selected.length === 0) {
        indicator.textContent = 'Click an option above, then return to the terminal';
      } else if (selected.length === 1) {
        const label = selected[0].querySelector('h3, .card-body h3')?.textContent?.trim() || selected[0].dataset.choice;
        indicator.innerHTML = '<span class="selected-text">' + label + ' selected</span> — return to terminal to continue';
      } else {
        indicator.innerHTML = '<span class="selected-text">' + selected.length + ' selected</span> — return to terminal to continue';
      }
    }, 0);
  });

  // Legacy: toggleSelect for old onclick handlers
  window.toggleSelect = function(el) {
    const container = el.closest('.options') || el.closest('.cards');
    const multi = container && container.dataset.multiselect !== undefined;
    if (container && !multi) {
      container.querySelectorAll('.option, .card').forEach(o => o.classList.remove('selected'));
    }
    if (multi) {
      el.classList.toggle('selected');
    } else {
      el.classList.add('selected');
    }
    window.selectedChoice = el.dataset.choice;
  };

  // Expose API
  window.selectedChoice = null;
  window.brainstorm = {
    send: sendEvent,
    choice: (value, metadata = {}) => sendEvent({ type: 'choice', value, ...metadata })
  };

  // Init
  connect();

  // Wait for DOM to be ready for v2 init
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initV2);
  } else {
    initV2();
  }
})();

const crypto = require('crypto');
const http = require('http');
const fs = require('fs');
const path = require('path');

// ========== WebSocket Protocol (RFC 6455) ==========

const OPCODES = { TEXT: 0x01, CLOSE: 0x08, PING: 0x09, PONG: 0x0A };
const WS_MAGIC = '258EAFA5-E914-47DA-95CA-C5AB0DC85B11';

function computeAcceptKey(clientKey) {
  return crypto.createHash('sha1').update(clientKey + WS_MAGIC).digest('base64');
