function initDesignFrame() {
  const preset = document.getElementById('vc-device-preset');
  const frame = document.getElementById('vc-design-frame');
  const label = document.getElementById('vc-viewport-label');

  if (!preset || !frame) return;

  function setViewport(value) {
    if (value === 'fluid') {
      frame.style.width = '';
      frame.style.height = '';
      frame.classList.add('vc-frame-fluid');
      if (label) label.textContent = '';
    } else {
      const [w, h] = value.split('x').map(Number);
      frame.style.width = w + 'px';
      frame.style.height = h + 'px';
      frame.classList.remove('vc-frame-fluid');
      if (label) label.textContent = w + '×' + h;
    }
  }

  preset.addEventListener('change', () => setViewport(preset.value));
}
